import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"毛主席纪念堂","description":"","frontmatter":{},"headers":[],"relativePath":"history/mausoleum.md","filePath":"history/mausoleum.md","lastUpdated":1784712887000}'),o={name:"history/mausoleum.md"};function n(i,t,s,d,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="毛主席纪念堂" tabindex="-1">毛主席纪念堂 <a class="header-anchor" href="#毛主席纪念堂" aria-label="Permalink to &quot;毛主席纪念堂&quot;">​</a></h1><blockquote><p>&quot;伟大领袖和导师毛泽东主席永垂不朽！&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>毛主席纪念堂位于天安门广场南端，是为纪念中国共产党中央委员会主席、中央军事委员会主席、政协全国委员会名誉主席毛泽东而建造的纪念性建筑。纪念堂内安放着毛泽东主席的遗体，供人们瞻仰。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">周二至周日 8:00-12:00（特殊日期除外）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>注意事项</strong></td><td style="text-align:left;">存包、安检，保持肃静</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁1号线天安门东站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区天安门广场南端</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="建堂缘起" tabindex="-1">建堂缘起 <a class="header-anchor" href="#建堂缘起" aria-label="Permalink to &quot;建堂缘起&quot;">​</a></h3><p>1976年9月9日，毛泽东主席逝世。中共中央决定，在首都北京建立毛主席纪念堂，安放毛泽东主席遗体，供人民瞻仰。</p><h3 id="建设" tabindex="-1">建设 <a class="header-anchor" href="#建设" aria-label="Permalink to &quot;建设&quot;">​</a></h3><p>1976年11月，毛主席纪念堂奠基动工，1977年5月落成，1977年9月9日正式开放。建设历时仅8个月，充分体现了中国人民对毛泽东主席的崇敬之情。</p><h3 id="设计" tabindex="-1">设计 <a class="header-anchor" href="#设计" aria-label="Permalink to &quot;设计&quot;">​</a></h3><p>纪念堂由著名建筑师主持设计，采用传统的宫殿式建筑风格，庄严肃穆。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="外观" tabindex="-1">外观 <a class="header-anchor" href="#外观" aria-label="Permalink to &quot;外观&quot;">​</a></h3><p>毛主席纪念堂坐南朝北，面对天安门，与天安门、人民英雄纪念碑在同一中轴线上。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">33.6米</td></tr><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">约2.8万平方米</td></tr><tr><td style="text-align:left;"><strong>结构</strong></td><td style="text-align:left;">正方形，基座和堂顶均为正方形</td></tr><tr><td style="text-align:left;"><strong>风格</strong></td><td style="text-align:left;">传统宫殿式</td></tr></tbody></table><h3 id="基座" tabindex="-1">基座 <a class="header-anchor" href="#基座" aria-label="Permalink to &quot;基座&quot;">​</a></h3><p>纪念堂基座高4米，采用红色花岗石贴面，象征革命。</p><h3 id="柱廊" tabindex="-1">柱廊 <a class="header-anchor" href="#柱廊" aria-label="Permalink to &quot;柱廊&quot;">​</a></h3><p>纪念堂正面有44根花岗石廊柱，每根高17.5米，柱间镶嵌着汉白玉石雕花饰。</p><h3 id="匾额" tabindex="-1">匾额 <a class="header-anchor" href="#匾额" aria-label="Permalink to &quot;匾额&quot;">​</a></h3><p>纪念堂北门楣上悬挂着&quot;毛主席纪念堂&quot;六个金色大字，由华国锋题写。</p><h3 id="南门" tabindex="-1">南门 <a class="header-anchor" href="#南门" aria-label="Permalink to &quot;南门&quot;">​</a></h3><p>南门上方悬挂着&quot;伟大领袖和导师毛泽东主席永垂不朽&quot;金字匾。</p><h2 id="内部布局" tabindex="-1">内部布局 <a class="header-anchor" href="#内部布局" aria-label="Permalink to &quot;内部布局&quot;">​</a></h2><h3 id="北大厅" tabindex="-1">北大厅 <a class="header-anchor" href="#北大厅" aria-label="Permalink to &quot;北大厅&quot;">​</a></h3><p>北大厅是瞻仰遗容的入口，厅内安放着毛泽东主席的汉白玉坐像。坐像高3.5米，背后是一幅巨大的绒绣壁画《祖国大地》。</p><h3 id="瞻仰厅" tabindex="-1">瞻仰厅 <a class="header-anchor" href="#瞻仰厅" aria-label="Permalink to &quot;瞻仰厅&quot;">​</a></h3><p>瞻仰厅位于纪念堂的核心位置，安放着毛泽东主席的水晶棺。</p><h4 id="水晶棺" tabindex="-1">水晶棺 <a class="header-anchor" href="#水晶棺" aria-label="Permalink to &quot;水晶棺&quot;">​</a></h4><ul><li><strong>材质</strong>：东海水晶</li><li><strong>工艺</strong>：特级水晶熔制，透明度极高</li><li><strong>尺寸</strong>：长2.2米，宽1米，高0.5米</li><li><strong>特点</strong>：可永久保存遗体</li></ul><h4 id="遗体" tabindex="-1">遗体 <a class="header-anchor" href="#遗体" aria-label="Permalink to &quot;遗体&quot;">​</a></h4><p>毛泽东主席的遗体身着灰色中山装，覆盖着中国共产党党旗，安详地躺在水晶棺中。</p><h4 id="环境控制" tabindex="-1">环境控制 <a class="header-anchor" href="#环境控制" aria-label="Permalink to &quot;环境控制&quot;">​</a></h4><p>瞻仰厅采用恒温、恒湿、隔菌技术，确保遗体长期保存。室内温度保持在20°C左右，湿度保持在60%左右。</p><h3 id="南大厅" tabindex="-1">南大厅 <a class="header-anchor" href="#南大厅" aria-label="Permalink to &quot;南大厅&quot;">​</a></h3><p>南大厅是瞻仰遗容的出口，厅内汉白玉石墙上镌刻着毛泽东主席手书的《满江红·和郭沫若同志》。</p><h3 id="毛泽东革命业绩纪念室" tabindex="-1">毛泽东革命业绩纪念室 <a class="header-anchor" href="#毛泽东革命业绩纪念室" aria-label="Permalink to &quot;毛泽东革命业绩纪念室&quot;">​</a></h3><p>纪念堂内设有毛泽东革命业绩纪念室，通过图片、文物、文献等，展示毛泽东主席的革命生涯和丰功伟绩。</p><h2 id="纪念物" tabindex="-1">纪念物 <a class="header-anchor" href="#纪念物" aria-label="Permalink to &quot;纪念物&quot;">​</a></h2><p>纪念堂内陈列着全国各地送来的珍贵纪念物：</p><ul><li><strong>珠穆朗玛峰岩石</strong>：象征祖国山河</li><li><strong>台湾日月潭泥土</strong>：象征祖国统一</li><li><strong>南海珊瑚</strong>：象征祖国辽阔海疆</li><li><strong>长征火箭模型</strong>：象征科技发展</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="开放时间" tabindex="-1">开放时间 <a class="header-anchor" href="#开放时间" aria-label="Permalink to &quot;开放时间&quot;">​</a></h3><ul><li><strong>常规开放</strong>：周二至周日 8:00-12:00</li><li><strong>特殊日期</strong>：重大节日期间可能调整</li><li><strong>关闭时间</strong>：周一闭馆</li></ul><h3 id="入场流程" tabindex="-1">入场流程 <a class="header-anchor" href="#入场流程" aria-label="Permalink to &quot;入场流程&quot;">​</a></h3><ol><li><strong>存包</strong>：所有包袋必须寄存（免费）</li><li><strong>安检</strong>：严格安检，禁止携带违禁品</li><li><strong>排队</strong>：排队等候入场</li><li><strong>瞻仰</strong>：依次瞻仰遗容</li><li><strong>出场</strong>：从南大厅出场</li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">事项</th><th style="text-align:left;">要求</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>着装</strong></td><td style="text-align:left;">衣冠整洁，穿长裤，不得穿拖鞋</td></tr><tr><td style="text-align:left;"><strong>行为</strong></td><td style="text-align:left;">脱帽，保持肃静，不得喧哗</td></tr><tr><td style="text-align:left;"><strong>禁止</strong></td><td style="text-align:left;">禁止拍照、录像、吸烟、吃东西</td></tr><tr><td style="text-align:left;"><strong>禁止</strong></td><td style="text-align:left;">禁止携带手机、相机、打火机</td></tr><tr><td style="text-align:left;"><strong>时间</strong></td><td style="text-align:left;">瞻仰时间有限，不得停留过久</td></tr></tbody></table><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">1号线天安门东站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">1路、2路、52路等天安门站</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>提前到达</strong>：建议提前到达，排队等候</li><li><strong>轻装前往</strong>：不要携带包袋，减少存包时间</li><li><strong>庄严肃穆</strong>：怀着崇敬之心瞻仰</li><li><strong>遵守规定</strong>：严格遵守各项规定</li><li><strong>特殊日期</strong>：节假日人较多，提前规划</li></ol><h2 id="历史意义" tabindex="-1">历史意义 <a class="header-anchor" href="#历史意义" aria-label="Permalink to &quot;历史意义&quot;">​</a></h2><p>毛主席纪念堂是毛泽东主席遗体的永久保存地，是全国各族人民瞻仰、缅怀伟大领袖的场所。</p><p>毛泽东主席是伟大的马克思主义者，伟大的无产阶级革命家、战略家、理论家，是中国共产党、中国人民解放军和中华人民共和国的主要创立者之一。</p><p>正如纪念堂南大厅的题词所说：</p><blockquote><p>&quot;伟大领袖和导师毛泽东主席永垂不朽！&quot;</p></blockquote><hr><p><strong>📍 地址</strong>：北京市东城区天安门广场南端 <strong>🚇 地铁</strong>：1号线天安门东站 <strong>⏰ 注意</strong>：开放时间可能调整，建议提前查询</p>',61)])])}const f=a(o,[["render",n]]);export{b as __pageData,f as default};
